import './CalendarYearView.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../../../helpers/classnames';
import { convertUtcToTz } from '../../newUtils';
import type { CalendarYearViewProps } from './CalendarYearView.types';
import { getYearsRange } from './utils';

export const CalendarYearView: FC<CalendarYearViewProps> = ({
	minYear = 1930,
	maxYear = new Date().getFullYear() + 10,
	selectedYear,
	viewDate,
	onSelectYear,
	showStartPanel,
	timeZone,
}) => {
	// Локальная дата:
	const userTz = convertUtcToTz(viewDate, timeZone);
	const currentYear = userTz.getFullYear();
	const years = getYearsRange(minYear, maxYear);

	const onClick = (year: number): void => {
		onSelectYear(year);
		// TODO точно это нужно? точно таким способом?
		typeof showStartPanel === 'function' && showStartPanel?.();
	};

	return (
		<div className="dsb_calendar-years">
			{years.map(year => {
				const selected = year === currentYear;
				return (
					<span
						data-testid={`year-${year}`}
						className={classNames('year', { selected })}
						onClick={() => onClick(year)}
						key={`year-${year}`}
					>
						{year}
					</span>
				);
			})}
		</div>
	);
};
